import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("QUOTE - base prices (first insurance, year 0, no other modifiers)", () => {
    // Base premium * 1.10 (first insurance) + 5 (fee), rounded up
    it.todo("quotes an empty item list at just the processing fee — 5 G");
    it.todo("quotes a plain sword at 115 G (100 * 1.10 + 5)");
    it.todo("quotes a plain amulet at 71 G (60 * 1.10 + 5)");
    it.todo("quotes a plain staff at 93 G (80 * 1.10 + 5)");
    it.todo("quotes a plain potion at 49 G (40 * 1.10 + 5)");
    it.todo("quotes a single rune at 33 G (25 * 1.10 = 27.5 → 28 + 5)");
    it.todo("quotes a single moonstone at 33 G (25 * 1.10 = 27.5 → 28 + 5)");
  });

  describe("QUOTE - component bundle special pricing", () => {
    it.todo("quotes 3 alike runes at the bundle price 71 G (60 * 1.10 + 5), not 3 * 33");
    it.todo("quotes 3 alike moonstones at the bundle price 71 G (60 * 1.10 + 5)");
  });

  describe("QUOTE - risk surcharges (single sword, first insurance, year 0)", () => {
    it.todo("adds 50% surcharge for a cursed sword — 170 G (100 * 1.5 * 1.10 + 5)");
    it.todo("adds 30% surcharge for a highly enchanted sword (enchantment 5) — 148 G (100 * 1.3 * 1.10 + 5)");
    it.todo("does not add the enchantment surcharge for enchantment 4 — 115 G");
    it.todo("stacks both surcharges for a cursed highly enchanted sword — 220 G (100 * 1.5 * 1.3 * 1.10 = 214.5 → 215 + 5)");
  });

  describe("QUOTE - customer discounts", () => {
    it.todo("applies 20% loyalty discount for a customer with 2 years — 93 G (100 * 0.8 * 1.10 + 5)");
    it.todo("does not apply loyalty discount for a customer with 1 year — 115 G");
    it.todo("applies 20% loyalty discount for a customer with 5 years — 93 G");
  });

  describe("QUOTE - contract sequence discounts", () => {
    it.todo("applies 10% first-insurance surcharge on the first quote — sword at 115 G");
    it.todo("applies 15% discount on the second quote in a scenario — sword at 90 G (100 * 0.85 + 5)");
    it.todo("applies 15% discount on the third quote in a scenario — sword at 90 G");
  });

  describe("QUOTE - rounding in MHPCO's favor", () => {
    it.todo("rounds fractional premiums up to whole G (rune 27.5 → 28, then + 5 = 33 G)");
  });

  describe("QUOTE - multiple items in one quote", () => {
    it.todo("sums premiums across mixed items with a single processing fee — sword + amulet at 181 G (115 - 5 + 71 - 5 + 5 = ?)");
  });

  describe("CLAIM - reimbursement rules", () => {
    it.todo("pays 0 for damage to an item that is neither high-enchantment nor dragon material");
    it.todo("pays 50% of damage minus 100 G deductible for an item with enchantment 8 — damage 400 → payout 100 G");
    it.todo("does not apply 50% rule for enchantment 7 — payout 0");
    it.todo("pays full damage minus 100 G deductible for a dragon-material item — damage 500 → payout 400 G");
    it.todo("applies a single 100 G deductible per damage event, not per damaged item");
    it.todo("sums reimbursements across multiple damaged items in one incident before subtracting the deductible");
    it.todo("never returns a negative payout (small damage below the deductible yields 0)");
  });

  describe("CLAIM - references the correct policy", () => {
    it.todo("uses the items from the policy identified by the zero-based policy index when matching itemType");
  });
});
